import json, re

with open('chart.html') as f:
    content = f.read()

match = re.search(r'var spec = (\{.*?\});', content, re.DOTALL)
if match:
    spec = json.loads(match.group(1))
    # Check color scale in detail
    for s in spec.get('scales', []):
        if s.get('name') == 'color':
            print('Color scale:', json.dumps(s, indent=2))
    # Check marks encode
    for m in spec.get('marks', []):
        encode = m.get('encode', {}).get('update', {})
        if 'fill' in encode:
            print('Fill encoding:', json.dumps(encode['fill'], indent=2))
        if 'fillScale' in encode:
            print('FillScale:', json.dumps(encode['fillScale'], indent=2))
"
